"""Normalization methods for spectral and metabolomics data."""import numpy as npdef minmax(X, axis=1):    """    Scale data to the range 0–1.    Parameters    ----------    X : array-like        Input data.    axis : int, default=1        Axis used for scaling. Use axis=1 to scale each sample/spectrum.    Returns    -------    X_scaled : ndarray        Min-max scaled data.    """    X = np.asarray(X, dtype=float)    X_min = np.min(X, axis=axis, keepdims=True)    X_max = np.max(X, axis=axis, keepdims=True)    denominator = X_max - X_min    denominator[denominator == 0] = 1    return (X - X_min) / denominator